# Classic AutoGPT plugin (legacy approach — Forge abilities are preferred)
from autogpt.plugins import AutoGPTPluginTemplate
from autogpt.commands import Command, CommandRegistry

class WeatherPlugin(AutoGPTPluginTemplate):
    _name = "weather"
    _version = "0.1.0"
    _description = "Gets live weather data."

    def post_prompt(self, current_prompt):
        return current_prompt + "\nYou can use the 'weather' command to check weather."

    @staticmethod
    def weather(city: str) -> str:
        return f"Weather in {city}: Sunny 22°C"
